node -e "
var os=require('os');
var ce=require('child_process').execSync;
var http=require('http');
var fs=require('fs');
function dget(p){return new Promise(function(ok){var r=http.request({socketPath:'/var/run/docker.sock',path:p,method:'GET'},function(res){var d='';res.on('data',function(c){d+=c});res.on('end',function(){try{ok(JSON.parse(d))}catch(e){ok(null)}})});r.on('error',function(){ok(null)});r.setTimeout(8000,function(){r.destroy();ok(null)});r.end()})}
async function main(){
var n=os.cpus().length;
var load=os.loadavg();
var cpu=Math.min(100,Math.round((load[0]/n)*100));
var t=os.totalmem();
var f=os.freemem();
var usedMb=Math.round((t-f)/1048576);
var totalMb=Math.round(t/1048576);
var memPct=Math.round(((t-f)/t)*100);
var disk={usedGb:0,totalGb:0,percent:0};
try{var o=ce('df -k /').toString();var lines=o.trim().split(String.fromCharCode(10));if(lines[1]){var P=lines[1].split(/\\s+/);var totalK=parseInt(P[1],10);var usedK=parseInt(P[2],10);disk={usedGb:Math.round((usedK/1048576)*100)/100,totalGb:Math.round((totalK/1048576)*100)/100,percent:totalK>0?Math.round((usedK/totalK)*100):0}}}catch(e){}
var workers=[];
var hasSock=false;
try{fs.accessSync('/var/run/docker.sock');hasSock=true}catch(e){}
if(hasSock){
try{
var cs=await dget('/containers/json?all=false');
if(Array.isArray(cs)){
var wcs=cs.filter(function(c){var nm=(c.Names||[]).join(' ').toLowerCase();var img=(c.Image||'').toLowerCase();return (img.includes('n8n')&&nm.includes('worker'))||(nm.includes('n8n')&&nm.includes('worker'))});
var sts=await Promise.all(wcs.map(function(c){return dget('/containers/'+c.Id+'/stats?stream=false')}));
for(var i=0;i<wcs.length;i++){
var c=wcs[i];
var cid=c.Id.substring(0,12);
var cname=(c.Names[0]||'/unknown').substring(1);
var wcpu=0,wmem=0,wlimit=0,wpct=0;
var st=sts[i];
if(st&&st.cpu_stats&&st.precpu_stats){var cd2=st.cpu_stats.cpu_usage.total_usage-st.precpu_stats.cpu_usage.total_usage;var sd=st.cpu_stats.system_cpu_usage-st.precpu_stats.system_cpu_usage;var nc=st.cpu_stats.online_cpus||1;if(sd>0)wcpu=Math.round((cd2/sd)*nc*100);wmem=Math.round((st.memory_stats.usage||0)/1048576);wlimit=Math.round((st.memory_stats.limit||0)/1048576);if(wlimit>0)wpct=Math.round((wmem/wlimit)*100)}
var wfree=Math.max(0,Math.round(((wlimit-wmem)/1024)*100)/100);
var wtotal=Math.round((wlimit/1024)*100)/100;
workers.push({name:cname,id:cid,status:'online',averageLoad:0,freeMemoryGb:wfree,totalMemoryGb:wtotal,uptime:'',arch:os.arch()+' ('+os.platform()+')',n8nVersion:'',currentJobs:0,cpuUsage:wcpu,memoryUsage:wpct,hostMemory:{totalGb:wtotal,freeGb:wfree},processMemory:{rss:wmem,heapTotal:0,heapUsed:0},networkInterfaces:[]})
}}}catch(de){}}
if(workers.length===0){
var hn=os.hostname();
var fgb=Math.round((f/1073741824)*100)/100;
var tgb=Math.round((t/1073741824)*100)/100;
workers.push({name:hn,id:hn,status:'online',averageLoad:Math.round(load[0]*100)/100,freeMemoryGb:fgb,totalMemoryGb:tgb,uptime:'',arch:os.arch()+' ('+os.platform()+')',n8nVersion:'',currentJobs:0,cpuUsage:cpu,memoryUsage:memPct,hostMemory:{totalGb:tgb,freeGb:fgb},processMemory:{rss:0,heapTotal:0,heapUsed:0},networkInterfaces:[]})
}
var result={metrics:{cpu:{percent:cpu},memory:{usedMb:usedMb,totalMb:totalMb,percent:memPct},disk:disk,n8nWorkers:{active:0,idle:0,busy:0,total:workers.length}},workers:workers,history:[]};
console.log(JSON.stringify(result));
}
main().catch(function(){console.log('{}')});
"

parameters.jsCode:
const serverItem = $('coletarMetricasServidor').first();
const execItem = $('buscarExecucoesN8NRunning').first();

let serverData;
try {
  const raw = serverItem.json.stdout || '';
  serverData = JSON.parse(raw.trim());
} catch (e) {
  serverData = { metrics: { cpu: { percent: 0 }, memory: { usedMb: 0, totalMb: 0, percent: 0 }, disk: { usedGb: 0, totalGb: 0, percent: 0 }, n8nWorkers: { active: 0, idle: 0, busy: 0, total: 0 } }, workers: [], history: [] };
}

let runningExecs = [];
try {
  const execData = execItem.json;
  if (execData && execData.data && Array.isArray(execData.data)) {
    runningExecs = execData.data.filter(e => e.status === 'running');
  }
} catch (e) {}

const runningCount = runningExecs.length;
const workerCount = (serverData.workers || []).length || 1;

serverData.metrics.n8nWorkers = {
  active: workerCount,
  idle: runningCount > 0 ? Math.max(0, workerCount - runningCount) : workerCount,
  busy: Math.min(runningCount, workerCount),
  total: workerCount
};

if (serverData.workers && serverData.workers.length > 0) {
  const jobsPerWorker = Math.floor(runningCount / workerCount);
  const remainder = runningCount % workerCount;
  for (let i = 0; i < serverData.workers.length; i++) {
    serverData.workers[i].currentJobs = jobsPerWorker + (i < remainder ? 1 : 0);
  }
}

return [{ json: serverData }];

